export function formatIDR(n: number): string {
  return "Rp " + Math.round(n).toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",");
}

const normalize = (s: string) =>
  s.toLowerCase()
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
    .replace(/[''`]/g, "")
    .replace(/\(.*?\)/g, "")
    .replace(/[^a-z0-9]+/g, " ")
    .trim();

export function getBoatByUrl(url?: string): Boat | undefined {
  if (!url) return undefined;
  return BOATS.find((b) => b.url === url);
}

export function getBoatByName(name?: string): Boat | undefined {
  if (!name) return undefined;
  const n = normalize(name);
  return BOATS.find((b) => normalize(b.name) === n)
    ?? BOATS.find((b) => normalize(b.name).split(" ")[0] === n.split(" ")[0] && n.startsWith(normalize(b.name)));
}

import { getCruisePriceOverride } from "./cruise-price-overrides";
import { useI18n, useT } from "@/contexts/i18n";

export function getCruisePriceNumeric(websiteOrName?: string, name?: string): number | null {
  const override = getCruisePriceOverride(name) ?? getCruisePriceOverride(websiteOrName);
  if (override !== undefined) {
    return typeof override === "number" ? override : null;
  }
  const boat = getBoatByUrl(websiteOrName) ?? getBoatByName(name) ?? getBoatByName(websiteOrName);
  return boat ? boat.priceIDR : null;
}

/** Static IDR label — kept for places that don't need currency conversion or where the hook can't be used. */
export function getCruisePriceLabel(websiteOrName?: string, name?: string): { price: string; unit: string; numeric: number | null } | null {
  const override = getCruisePriceOverride(name) ?? getCruisePriceOverride(websiteOrName);
  if (override !== undefined) {
    if (override === "partner") {
      return { price: "Sur demande", unit: "voir partenaire", numeric: null };
    }
    return { price: formatIDR(override), unit: "/pers", numeric: override };
  }
  const boat = getBoatByUrl(websiteOrName) ?? getBoatByName(name) ?? getBoatByName(websiteOrName);
  if (!boat) return null;
  return {
    price: formatIDR(boat.priceIDR),
    unit: boat.priceType === "perPerson" ? "/pers" : "/charter",
    numeric: boat.priceIDR,
  };
}

/** Hook: currency-aware price label for the current user's selected currency. */
export function useCruisePriceLabel(websiteOrName?: string, name?: string): { price: string; unit: string; numeric: number | null } | null {
  const { formatPriceFromIDR } = useI18n();
  const t = useT();
  const override = getCruisePriceOverride(name) ?? getCruisePriceOverride(websiteOrName);
  if (override !== undefined) {
    if (override === "partner") {
      return { price: "Sur demande", unit: "voir partenaire", numeric: null };
    }
    return { price: formatPriceFromIDR(override), unit: t("perPerson"), numeric: override };
  }
  const boat = getBoatByUrl(websiteOrName) ?? getBoatByName(name) ?? getBoatByName(websiteOrName);
  if (!boat) return null;
  return {
    price: formatPriceFromIDR(boat.priceIDR),
    unit: boat.priceType === "perPerson" ? t("perPerson") : "/charter",
    numeric: boat.priceIDR,
  };
}

